/* Live rates: calls the Netlify function that proxies England Logistics.
   Returns {live:true,rates:[...]} on success, or null so callers fall back
   to the local estimate. Works on the deployed Netlify site; in the chat
   preview there's no backend so it simply returns null (estimate is used). */
const RATES_ENDPOINT="/.netlify/functions/quote";
async function getLiveRates(s,england){
  if(!england||!england.enabled) return null;
  const body={token:CLOUD.token||undefined,carriers:s.carriers||"fedex",fromZip:s.fromZip,toZip:s.toZip,fromCountry:s.fromCountry||"US",toCountry:s.toCountry||"US",residential:!!s.residential,signature:!!s.signature,signatureOption:s.signatureOption||(s.signature?"direct":"none"),saturdayDelivery:!!s.saturdayDelivery,insuranceAmount:s.insuranceAmount||null,packageTypeCode:s.packageTypeCode||"",fedexAccount:(england.fedexAccount||null),pieces:(s.pieces||[]).map(p=>({weight:Math.ceil(+p.weight||1),length:+p.L||12,width:+p.W||9,height:+p.H||4,declaredValue:(+p.declaredValue||0)||undefined})),account:{base:england.base,apiKey:england.apiKey,customerId:england.customerId}};   /* FedEx bills every fractional pound as the next full pound (3 lb 3 oz rates as 4 lb) — round up here so the quote is the invoice price */
  const attempt=async(ms)=>{
    const ctrl=new AbortController();const t=setTimeout(()=>ctrl.abort(),ms);
    try{
      const r=await fetch(RATES_ENDPOINT,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(body),signal:ctrl.signal});
      clearTimeout(t);
      let data=null; try{data=await r.json();}catch(e){ try{data={error:await r.text()};}catch(e2){} }
      if(data&&typeof data==="object") return data;
      if(!r.ok) return {live:false,error:`Server ${r.status}`,rates:[]};
      return {live:false,error:"Empty response from server",rates:[]};
    }catch(e){ clearTimeout(t); return {live:false,_transient:true,error:(e&&e.name==="AbortError")?"The rate server took too long to respond":((e&&e.message)||"Network error"),rates:[]}; }
  };
  try{
    let res=await attempt(25000);
    // one automatic retry if the first attempt timed out or hit a network error (not on a real England error like 401)
    if(res&&res._transient&&(!res.rates||!res.rates.length)){ res=await attempt(25000); }
    return res;
  }catch(e){ return {live:false,error:(e&&e.message)||"Network error",rates:[]}; }
}
const SHIP_ENDPOINT="/.netlify/functions/ship";
function acctOf(england){return {base:england.base,apiKey:england.apiKey,customerId:england.customerId,integrationId:england.integrationId,fedexAccount:england.fedexAccount||null};}
/* Per-client England accounts: if the client has their own England customer ID + API key
   (England bakes their markup into that account's rates), quotes and bookings run on THEIR
   account. Otherwise they fall back to the main account in Settings. The global "Use live
   England rates" toggle stays the master switch; base URL is inherited unless overridden. */
function englandFor(client,settings){
  // Single-account model: everything ships on the one account entered in
  // Settings → Carrier accounts. Per-customer England fields are ignored so a stray
  // customer entry can never shadow the working account.
  // fedexAccount is the ONE per-customer override: the FedEx account number the direct FedEx
  // quote/ship functions rate and book on. A number typed on the login's own FedEx Account
  // settings page wins (so what the customer sees in that field is always what actually
  // applies), then the company default the admin set on Customers → FedEx Account, then the
  // FEDEX_ACCOUNT env default.
  const g=(settings&&settings.england)||{};
  return {...g,_src:"main",fedexAccount:String(g.fedexAccount||"").trim()||(client&&client.fedex&&String(client.fedex.accountNumber||"").trim())||""};
}
