/* ════════ PRIMITIVES ════════ */
// Smart paste: turn a pasted contact/address blob into structured fields.
const US_STATE_ABBRS=new Set(["AL","AK","AZ","AR","CA","CO","CT","DE","FL","GA","HI","ID","IL","IN","IA","KS","KY","LA","ME","MD","MA","MI","MN","MS","MO","MT","NE","NV","NH","NJ","NM","NY","NC","ND","OH","OK","OR","PA","RI","SC","SD","TN","TX","UT","VT","VA","WA","WV","WI","WY","DC","PR"]);
const STATE_NAME_TO_ABBR={"alabama":"AL","alaska":"AK","arizona":"AZ","arkansas":"AR","california":"CA","colorado":"CO","connecticut":"CT","delaware":"DE","florida":"FL","georgia":"GA","hawaii":"HI","idaho":"ID","illinois":"IL","indiana":"IN","iowa":"IA","kansas":"KS","kentucky":"KY","louisiana":"LA","maine":"ME","maryland":"MD","massachusetts":"MA","michigan":"MI","minnesota":"MN","mississippi":"MS","missouri":"MO","montana":"MT","nebraska":"NE","nevada":"NV","new hampshire":"NH","new jersey":"NJ","new mexico":"NM","new york":"NY","north carolina":"NC","north dakota":"ND","ohio":"OH","oklahoma":"OK","oregon":"OR","pennsylvania":"PA","rhode island":"RI","south carolina":"SC","south dakota":"SD","tennessee":"TN","texas":"TX","utah":"UT","vermont":"VT","virginia":"VA","washington":"WA","west virginia":"WV","wisconsin":"WI","wyoming":"WY","district of columbia":"DC","puerto rico":"PR"};
function parseCSZ(seg){
  const out={}; seg=String(seg||"").trim();
  const zip=seg.match(/\b(\d{5})(?:-\d{4})?\b/);
  if(zip){ out.zip=zip[1]; seg=(seg.slice(0,zip.index)+" "+seg.slice(zip.index+zip[0].length)).trim(); }
  seg=seg.replace(/[,\s]+$/,"").trim();
  const ab=seg.match(/(?:^|[\s,])([A-Za-z]{2})$/);
  if(ab&&US_STATE_ABBRS.has(ab[1].toUpperCase())){ out.state=ab[1].toUpperCase(); seg=seg.slice(0,seg.length-ab[1].length).replace(/[,\s]+$/,"").trim(); }
  else { const fn=Object.keys(STATE_NAME_TO_ABBR).sort((a,b)=>b.length-a.length).find(n=>new RegExp("(?:^|[\\s,])"+n+"$","i").test(seg)); if(fn){ out.state=STATE_NAME_TO_ABBR[fn]; seg=seg.replace(new RegExp(fn+"$","i"),"").replace(/[,\s]+$/,"").trim(); } }
  seg=seg.replace(/[,\s]+$/,"").trim();
  if(seg) out.city=seg.replace(/,/g,"").trim();
  return out;
}
function stripTrailingCity(addr,city){
  if(!addr||!city) return addr;
  const esc=String(city).trim().replace(/[.*+?^${}()|[\]\\]/g,"\\$&");
  const out=String(addr).replace(new RegExp("[\\s,]*"+esc+"\\s*,?\\s*$","i"),"").replace(/[\s,]+$/,"").trim();
  return out||addr;
}
function parseAddressBlob(raw){
  const out={};
  let text=String(raw||"").replace(/\r/g,"").trim();
  if(!text) return out;
  // un-glue a lost line break like "960 SAmerican Fork" → "960 S American Fork"
  text=text.replace(/\b([NSEW])([A-Z][a-z])/g,"$1 $2");
  const em=text.match(/[a-z0-9._%+\-]+@[a-z0-9.\-]+\.[a-z]{2,}/i);
  if(em){ out.email=em[0]; text=text.replace(em[0]," "); }
  const ph=text.match(/(\+?1[\s.\-]?)?\(?\d{3}\)?[\s.\-]?\d{3}[\s.\-]?\d{4}(?!\d)/);
  if(ph&&ph[0].replace(/\D/g,"").length>=10){ out.phone=ph[0].replace(/\s+/g," ").trim(); text=text.replace(ph[0]," "); }
  const ctry=text.match(/\b(United States of America|United States|U\.?S\.?A\.?|USA|Canada|Mexico)\b/i);
  if(ctry){ const c=ctry[0].toLowerCase(); out.country=/can/.test(c)?"Canada":(/mex/.test(c)?"Mexico":"United States"); text=text.replace(ctry[0]," "); }
  let lines=text.split(/\n+/).map(s=>s.replace(/[ \t]+/g," ").trim()).filter(Boolean);
  if(lines.length===1&&lines[0].includes(",")) lines=lines[0].split(",").map(s=>s.trim()).filter(Boolean);
  let cszIdx=lines.findIndex(l=>/\b\d{5}(-\d{4})?\b/.test(l));
  if(cszIdx>=0){
    let csz=parseCSZ(lines[cszIdx]);
    if(!csz.city&&cszIdx>0&&!/^\s*\d/.test(lines[cszIdx-1])){ const merged=parseCSZ(lines[cszIdx-1]+" "+lines[cszIdx]); if(merged.city){ csz=merged; lines.splice(cszIdx-1,1); cszIdx--; } }
    if(csz.zip)out.zip=csz.zip; if(csz.state)out.state=csz.state; if(csz.city)out.city=csz.city;
    lines.splice(cszIdx,1);
  }
  const stRe=/^\s*(\d+[-\w]*|(?:po|p\.o\.)\s*box)\s+\S/i;
  const aptRe=/\b(apt|apartment|suite|ste|unit|bldg|building|floor|fl|rm|room|dept)\b\.?\s*\S|#\s*\w/i;
  const addrIdx=lines.findIndex(l=>stRe.test(l));
  if(addrIdx>=0){ out.address1=lines[addrIdx]; lines.splice(addrIdx,1); }
  const aptIdx=lines.findIndex(l=>aptRe.test(l));
  if(aptIdx>=0){ out.address2=lines[aptIdx]; lines.splice(aptIdx,1); }
  const compRe=/\b(inc|llc|corp|corporation|company|co|ltd|limited|lp|llp|plc|group|holdings|enterprises|services|logistics|industries|systems|solutions|associates|partners|freight|shipping|warehouse|distribution)\b\.?/i;
  const rem=lines.filter(Boolean);
  if(rem.length){
    let ci=rem.findIndex(l=>compRe.test(l));
    if(ci>=0){ out.company=rem[ci]; rem.splice(ci,1); }
    if(rem.length){ out.name=rem[0]; rem.splice(0,1); }
    if(rem.length&&!out.company){ out.company=rem[0]; }
  }
  if(out.address1&&out.city) out.address1=stripTrailingCity(out.address1,out.city);
  return out;
}
function AddressCard({title,data,set,required,residential,setResidential,addresses,onPick,onSave,errorFields=[],contactFallback,side,hideAddr23,reqOverrides={},headerExtra=null,scanSlot=null,defaultEntry=null}){
  const f=(k,v)=>set({...data,[k]:v});
  // Smart paste: if the pasted text parses into 2+ fields, distribute it across the whole form instead of one field
  const onSmartPaste=(e)=>{
    const txt=((e.clipboardData||window.clipboardData)&&(e.clipboardData||window.clipboardData).getData("text"))||"";
    const parsed=parseAddressBlob(txt);
    const keys=Object.keys(parsed).filter(k=>parsed[k]);
    if(keys.length<2) return;   // single value → let the normal paste land in this field
    e.preventDefault();
    set(prev=>{ const next={...prev}; for(const k of keys) next[k]=parsed[k]; return next; });
  };
  const [q,setQ]=useState("");
  const [open,setOpen]=useState(false);
  const [savedOk,setSavedOk]=useState(false);
  const _fmt=addrFmtFor(data.country);                                   // country-specific field names & requiredness
  const _acCountry=_isUSCountry(data.country)?"us":(iso2For(data.country)||"").toLowerCase();   // ""=global search
  // Google Places autocomplete on Address 1
  const [acSug,setAcSug]=useState([]);
  const [acOpen,setAcOpen]=useState(false);
  const [acBusy,setAcBusy]=useState(false);
  const sessionRef=React.useRef(Math.random().toString(36).slice(2));
  const acSkip=React.useRef(false); // skip the autocomplete fetch right after we fill from a pick
  const acFocusRef=React.useRef(false); // only show suggestions while the user is actively in the field
  useEffect(()=>{
    const v=String(data.address1||"").trim();
    if(acSkip.current){acSkip.current=false;return;}
    if(!acFocusRef.current){setAcOpen(false);return;}   // don't auto-open on page load / programmatic fills
    if(v.length<3){setAcSug([]);setAcOpen(false);return;}
    let cancel=false;
    const t=setTimeout(async()=>{
      setAcBusy(true);
      const r=await placesCall({action:"autocomplete",input:v,session:sessionRef.current,country:_acCountry});
      if(cancel)return;
      setAcBusy(false);
      if(r&&r.ok&&r.predictions&&r.predictions.length&&acFocusRef.current){setAcSug(r.predictions);setAcOpen(true);}
      else {setAcSug([]);setAcOpen(false);}
    },300);
    return ()=>{cancel=true;clearTimeout(t);};
  },[data.address1,_acCountry]);
  const pickPlace=async(p)=>{
    acFocusRef.current=false;setAcOpen(false);setAcSug([]);setAcBusy(true);   // hard-close the dropdown immediately
    const r=await placesCall({action:"details",placeId:p.placeId,session:sessionRef.current});
    setAcBusy(false);
    sessionRef.current=Math.random().toString(36).slice(2);
    if(r&&r.ok&&r.address){
      const a=r.address;acSkip.current=true;
      set(prev=>({...prev,address1:a.address1||prev.address1,city:a.city||prev.city,state:a.state||prev.state,zip:a.zip||prev.zip,country:a.country||prev.country||"United States"}));
    }
  };
  const saveToBook=()=>{ if(onSave){onSave(data);setSavedOk(true);setTimeout(()=>setSavedOk(false),1600);} };
  // Auto-fill city + state when a 5-digit ZIP is entered
  const lastZip=React.useRef("");
  useEffect(()=>{
    const zip=String(data.zip||"").trim();
    if(!/^\d{5}$/.test(zip)||zip===lastZip.current)return;
    lastZip.current=zip;
    let cancel=false;
    const t=setTimeout(()=>{
      fetch("https://api.zippopotam.us/us/"+zip).then(r=>r.ok?r.json():null).then(d=>{
        if(cancel||!d||!d.places||!d.places[0])return;
        const p=d.places[0];
        set(prev=>{ const city=p["place name"]||prev.city; const a1=stripTrailingCity(prev.address1||"", p["place name"]); return {...prev,city,state:p["state abbreviation"]||prev.state,address1:a1}; });
      }).catch(()=>{});
    },400);
    return ()=>{cancel=true;clearTimeout(t);};
  },[data.zip]);
  const matches=(addresses||[]).filter(a=>!q.trim()||[a.name,a.company,a.city,a.zip,a.address1].filter(Boolean).some(v=>String(v).toLowerCase().includes(q.toLowerCase()))).slice(0,12);
  const pick=(a)=>{const cf=contactFallback||{};set({...data,name:a.name||"",company:a.company||"",address1:a.address1||"",address2:a.address2||"",city:a.city||"",state:a.state||"",zip:a.zip||"",country:a.country||data.country||"United States",phone:a.phone||cf.phone||"",email:a.email||cf.email||""});setQ("");setOpen(false);onPick&&onPick(a);};
  // cell() is a plain render helper (NOT a component) so inputs never remount → focus is kept while typing
  const abList=Array.isArray(addresses)?addresses:[];
  const abKey=(title||"").replace(/\s/g,"");
  const abDatalists=abList.length?(<>
    <datalist id={"sc-ab-name-"+abKey}>{abList.filter(a=>a.name).map(a=><option key={"n"+a.id} value={a.name}>{a.company?a.company+" · ":""}{a.city||""}</option>)}</datalist>
    <datalist id={"sc-ab-company-"+abKey}>{abList.filter(a=>a.company).map(a=><option key={"c"+a.id} value={a.company}>{a.name?a.name+" · ":""}{a.city||""}</option>)}</datalist>
  </>):null;
  const cell=(label,k,span,req)=>(
    <div key={k} className={`px-2 py-1.5 ${k==="country"?"rounded-t-[7px]":k==="phone"?"rounded-bl-[7px]":k==="email"?"rounded-br-[7px]":""} ${errorFields.includes(k)?"bg-rose-50 relative z-10 shadow-[0_0_0_1.5px_#fda4af]":(req&&!data[k]?"bg-white relative z-10 shadow-[0_0_0_1.5px_#42a7ef]":"bg-white")} ${span||""} ${k==="address1"?"relative":""}`}>
      {!(k==="country"||k==="address2"||k==="address3")&&<div className={`text-[10px] uppercase tracking-wide ${errorFields.includes(k)?"text-rose-600 font-semibold":(req&&!data[k]?"text-[#0086E0]":"text-stone-400")} flex items-center gap-1`}>{label}{errorFields.includes(k)?" • required":""}{k==="address1"&&acBusy&&<Loader2 className="w-2.5 h-2.5 animate-spin text-stone-400"/>}</div>}
      {k==="country"
        ? <div className="flex items-center gap-2"><span className="text-[10px] uppercase tracking-wide text-stone-400 shrink-0">{label}</span><select value={data.country||"United States"} onChange={e=>f("country",e.target.value)} className="flex-1 bg-transparent text-[14px] leading-5 text-stone-900 outline-none">{COUNTRIES.map(c=><option key={c}>{c}</option>)}</select></div>
        : (k==="address2"||k==="address3")
        ? <div className="flex items-center gap-2"><span className="text-[10px] uppercase tracking-wide text-stone-400 shrink-0">{label}</span><input value={data[k]||""} onChange={e=>f(k,e.target.value)} onPaste={onSmartPaste} autoComplete="off" className="flex-1 bg-transparent text-[14px] leading-5 text-stone-900 outline-none placeholder-stone-300"/></div>
        : <input value={data[k]||""} onChange={e=>{const v=e.target.value;f(k,v);
            if((k==="name"||k==="company")&&Array.isArray(addresses)&&v.length>1){const hit=addresses.find(a=>(a.name&&a.name===v)||(a.company&&a.company===v));
              if(hit){set({...data,name:hit.name||"",company:hit.company||"",address1:hit.address1||"",address2:hit.address2||"",city:hit.city||"",state:hit.state||"",zip:hit.zip||"",country:hit.country||"United States",phone:hit.phone||data.phone||"",email:hit.email||data.email||""});if(onPick)onPick(hit);}}
          }} list={(k==="name"||k==="company")&&Array.isArray(addresses)&&addresses.length?("sc-ab-"+k+"-"+(title||"").replace(/\s/g,"")):undefined} onPaste={onSmartPaste} onFocus={k==="address1"?()=>{acFocusRef.current=true;if(acSug.length)setAcOpen(true);}:undefined} onBlur={k==="address1"?()=>setTimeout(()=>{acFocusRef.current=false;setAcOpen(false);},150):undefined} autoComplete="off" className="w-full bg-transparent text-[14px] leading-5 text-stone-900 outline-none mt-0.5 placeholder-stone-300"/>}
      {k==="address1"&&acOpen&&acSug.length>0&&<div className="absolute z-40 left-0 right-0 top-full mt-1 bg-white border border-stone-200 rounded-lg shadow-lg max-h-60 overflow-auto">
        <div className="px-3 py-1.5 text-[10px] uppercase tracking-widest text-stone-400 bg-stone-50 border-b border-stone-100 flex items-center gap-1"><MapPin className="w-3 h-3"/>Google Maps suggestions</div>
        <div className="divide-y divide-stone-100">
        {acSug.map(p=><button key={p.placeId} onMouseDown={(e)=>{e.preventDefault();pickPlace(p);}} className="w-full text-left px-3 py-2 hover:bg-[#E6F4FF] text-[13px] text-stone-700">{p.description}</button>)}
        </div>
      </div>}
    </div>
  );
  return (<div className="relative">
    {abDatalists}
    <div className="flex items-center justify-between mb-1.5">
      <span className="text-[#0086E0] font-semibold text-[15px] shrink-0">{title}</span>
      <div className="flex items-center gap-2">
        {setResidential&&<label className="flex items-center gap-1.5 text-[11px] cursor-pointer"><input type="checkbox" checked={residential} onChange={e=>setResidential(e.target.checked)} className="accent-[#0086E0]"/>{residential?<span className="flex items-center gap-1 text-[#006FBF]"><Home className="w-3.5 h-3.5"/>Residential</span>:<span className="flex items-center gap-1 text-stone-600"><Building2 className="w-3.5 h-3.5"/>Commercial</span>}</label>}
      </div>
    </div>
    {addresses!==undefined&&(
      <div className="flex flex-col lg:flex-row gap-4 mb-1.5 items-start">
      <div className="flex-1 min-w-0 flex items-center gap-1.5">
      <div className="relative flex-1 min-w-0">
        <Search className="w-3.5 h-3.5 absolute left-2.5 top-2.5 text-stone-400"/>
        <input value={q} onChange={e=>{setQ(e.target.value);setOpen(true);}} onFocus={()=>setOpen(true)} onBlur={()=>setTimeout(()=>setOpen(false),150)} placeholder={(addresses&&addresses.length)?`Address Book — ${addresses.length} Saved…`:"Search Address Book…"} className="w-full bg-white border border-stone-200 rounded pl-8 pr-8 py-1.5 text-[13px] outline-none focus:border-[#0086E0] placeholder-stone-300"/>
        <button type="button" onMouseDown={(e)=>{e.preventDefault();setOpen(o=>!o);}} className="absolute right-2 top-1.5 text-stone-400 hover:text-[#0086E0]" title="Show all saved addresses"><ChevronDown className={`w-4 h-4 transition-transform ${open?"rotate-180":""}`}/></button>
        {open&&matches.length===0&&<div className="absolute z-30 left-0 right-0 top-full mt-1 bg-white border border-stone-200 rounded-lg shadow-lg overflow-hidden">{defaultEntry&&<button onMouseDown={()=>pick(defaultEntry)} className="w-full text-left px-3 py-2 bg-[#F0F9FF] hover:bg-[#E6F4FF] border-b border-stone-100 flex items-center gap-2"><Home className="w-3.5 h-3.5 text-[#0086E0] shrink-0"/><span className="text-sm font-medium text-[#006FBF]">Default sender</span><span className="text-[11px] text-stone-400 truncate">{[defaultEntry.name||defaultEntry.company,defaultEntry.city].filter(Boolean).join(" · ")}</span></button>}<div className="px-3 py-2.5 text-xs text-stone-400">{(addresses&&addresses.length)?"No matches — try fewer letters.":"Nothing saved yet. Fill in an address and hit “Save to Address book” — it’ll be one click next time."}</div></div>}
        {open&&matches.length>0&&<div className="absolute z-30 left-0 right-0 top-full mt-1 bg-white border border-stone-200 rounded-lg shadow-lg max-h-64 overflow-auto">{defaultEntry&&<button onMouseDown={()=>pick(defaultEntry)} className="w-full text-left px-3 py-2 bg-[#F0F9FF] hover:bg-[#E6F4FF] border-b border-stone-100 flex items-center gap-2"><Home className="w-3.5 h-3.5 text-[#0086E0] shrink-0"/><span className="text-sm font-medium text-[#006FBF]">Default sender</span><span className="text-[11px] text-stone-400 truncate">{[defaultEntry.name||defaultEntry.company,defaultEntry.city].filter(Boolean).join(" · ")}</span></button>}
          <div className="px-3 py-1.5 text-[10px] uppercase tracking-widest text-stone-400 bg-stone-50 border-b border-stone-100 sticky top-0">{q.trim()?`${matches.length} match${matches.length===1?"":"es"}`:`${addresses.length} saved address${addresses.length===1?"":"es"}`}</div>
          <div className="divide-y divide-stone-100">
          {matches.map(a=><button key={a.id} onMouseDown={()=>pick(a)} className="w-full text-left px-3 py-2 hover:bg-[#E6F4FF]"><div className="text-sm font-medium text-stone-800">{a.name}{a.company?` · ${a.company}`:""}</div><div className="text-[11px] text-stone-400">{a.address1}{a.address1?", ":""}{a.city} {a.state} {a.zip}{a.acctNum?` · bill ${a.acctCarrier||""} ${a.acctNum}`:""}</div></button>)}
          </div>
        </div>}
      </div>
      {onSave&&<button type="button" onClick={saveToBook} disabled={!data.name&&!data.company} title={savedOk?"Saved to address book":"Save this address to your address book"} className={`shrink-0 h-[34px] w-[34px] flex items-center justify-center rounded-lg border ${savedOk?"bg-emerald-50 border-emerald-200 text-emerald-600":"bg-white border-stone-200 text-stone-400 hover:text-[#0086E0] hover:border-[#99D6FF] disabled:opacity-40"}`}>{savedOk?<Check className="w-4 h-4"/>:<Save className="w-4 h-4"/>}</button>}
      </div>
      {scanSlot&&<div className={side?"lg:w-[280px] xl:w-[330px] shrink-0 flex flex-col gap-1.5":"flex flex-col gap-1.5"}>
        {scanSlot}
      </div>}
      </div>
    )}
    {/* side (Address Check) is its OWN bordered box with a 12px gap — flex default stretch keeps
        both boxes' tops AND bottoms flush with the fields grid */}
    <div className={side?"flex flex-col lg:flex-row gap-4":""}>
    <div className={side?"flex-1 min-w-0 grid grid-cols-6 gap-px bg-stone-200 border border-stone-200 shadow-sm rounded-lg":"grid grid-cols-6 gap-px bg-stone-200 border border-stone-200 shadow-sm rounded-lg"}>
      {cell("Country","country","col-span-6")}{cell("Name","name","col-span-6 sm:col-span-3",required)}{cell("Company","company","col-span-6 sm:col-span-3",reqOverrides.company===true)}{cell("Address 1","address1","col-span-6",required)}{cell(_fmt.zip,"zip","col-span-3 sm:col-span-2",required&&!_fmt.zipOpt)}{cell(_fmt.state,"state","col-span-3 sm:col-span-2",required&&!_fmt.stateOpt)}{cell("City","city","col-span-6 sm:col-span-2",required)}{!hideAddr23&&<>{cell("Address 2","address2","col-span-6 sm:col-span-3")}{cell("Address 3","address3","col-span-6 sm:col-span-3")}</>}{cell("Phone","phone","col-span-6 sm:col-span-3",required&&reqOverrides.phone!==false)}{cell("Email","email","col-span-6 sm:col-span-3",required&&reqOverrides.email!==false)}
    </div>
    {side&&<div className="lg:w-[280px] xl:w-[330px] shrink-0 bg-stone-50 border border-stone-200 shadow-sm rounded-lg p-3">{side}</div>}
    </div>
  </div>);
}
function PkgInput({label,w,req,...p}){const ww=w||"w-14";const on=req&&!String(p.value??"").trim();return <div className={ww}><div className={`text-[10px] uppercase tracking-widest text-center ${on?"text-[#0086E0]":"text-stone-500"}`}>{label}</div><input placeholder="0" {...p} type="number" className={`w-full border rounded px-2 py-1 text-sm text-stone-900 outline-none focus:border-[#0086E0] placeholder-stone-300 text-center ${on?"bg-white border-[#42a7ef]":"bg-white border-stone-300"}`}/></div>;}
function Panel({title,children}){return <div className="border border-stone-200 rounded-lg bg-white p-4 space-y-3"><div className="text-[10px] uppercase tracking-widest text-stone-400">{title}</div>{children}</div>;}
function Field({label,children}){return <label className="block space-y-1"><span className="text-[11px] text-stone-500">{label}</span>{children}</label>;}
function Input({className="",...p}){return <input {...p} className={`w-full bg-white border border-stone-200 rounded px-2.5 py-2 text-sm text-stone-900 focus:border-[#0086E0] outline-none ${className}`}/>;}
/* Freely-typeable numeric box: type any number, it commits raw as you go and only clamps to
   [min,max] on blur. Local string state means the caret never jumps and you're never limited to
   one digit at a time (the old clamp-on-every-keystroke bug). External value changes sync in
   only while the box is NOT focused, so a background refresh can't clobber your typing. */
function NumBox({value,onCommit,min,max,fallback,className="",...rest}){
  const [txt,setTxt]=React.useState(value==null?"":String(value));
  const [focus,setFocus]=React.useState(false);
  React.useEffect(()=>{ if(!focus)setTxt(value==null?"":String(value)); },[value,focus]);
  const clamp=(n)=>{ let v=n; if(min!=null)v=Math.max(min,v); if(max!=null)v=Math.min(max,v); return v; };
  return <input type="number" inputMode="numeric" value={txt}
    onFocus={()=>setFocus(true)}
    onChange={e=>{ const raw=e.target.value; setTxt(raw); if(raw===""||raw==="-")return; const n=+raw; if(!isNaN(n))onCommit&&onCommit(n); }}
    onBlur={e=>{ setFocus(false); let n=+e.target.value; if(e.target.value===""||isNaN(n))n=(fallback!=null?fallback:(min!=null?min:0)); n=clamp(n); setTxt(String(n)); onCommit&&onCommit(n); }}
    className={className||"w-full bg-white border border-stone-200 rounded px-2.5 py-2 text-sm text-stone-900 focus:border-[#0086E0] outline-none"} {...rest}/>;
}
function Select({children,...p}){return <select {...p} className="w-full bg-white border border-stone-200 rounded-lg px-2.5 py-2 text-sm focus:border-[#0086E0] outline-none">{children}</select>;}
function Toggle({on,set,label}){return <button onClick={()=>set(!on)} className={`flex items-center gap-1.5 text-xs rounded px-2.5 py-1.5 border ${on?"bg-[#E6F4FF] border-[#99D6FF] text-[#0086E0]":"bg-white border-stone-200 text-stone-400"}`}><span className={`w-2 h-2 rounded-full ${on?"bg-[#0086E0]":"bg-stone-300"}`}/>{label}</button>;}
function Badge({children,tone="stone"}){const t={stone:"bg-stone-100 text-stone-500 border-stone-200",green:"bg-emerald-50 text-emerald-700 border-emerald-200",amber:"bg-amber-50 text-amber-700 border-amber-200",blue:"bg-[#E6F4FF] text-[#006FBF] border-[#99D6FF]",rose:"bg-rose-50 text-rose-600 border-rose-200",violet:"bg-violet-50 text-violet-700 border-violet-200"}[tone]||"bg-stone-100 text-stone-500 border-stone-200";return <span className={`text-[10px] uppercase tracking-wide rounded px-1.5 py-0.5 border ${t}`}>{children}</span>;}
/* "···" overflow menu for dense action rows. Portaled + fixed-position so overflow-hidden list
   containers can't clip it. Items: {label, onClick, title, danger, active} — falsy items skipped. */
function RowMenu({items,title="More actions"}){
  const vis=(items||[]).filter(Boolean);
  const [open,setOpen]=useState(false);
  const [pos,setPos]=useState({top:0,right:0});
  const btnRef=useRef(null);
  useEffect(()=>{ if(!open)return;
    const close=()=>setOpen(false);
    const key=(e)=>{ if(e.key==="Escape")setOpen(false); };
    window.addEventListener("click",close);
    window.addEventListener("scroll",close,true);
    window.addEventListener("resize",close);
    window.addEventListener("keydown",key);
    return ()=>{ window.removeEventListener("click",close); window.removeEventListener("scroll",close,true); window.removeEventListener("resize",close); window.removeEventListener("keydown",key); };
  },[open]);
  if(!vis.length)return null;
  const toggle=(e)=>{ e.stopPropagation(); if(open){setOpen(false);return;} const r=btnRef.current.getBoundingClientRect(); setPos({top:r.bottom+4,right:Math.max(8,window.innerWidth-r.right)}); setOpen(true); };
  return (<>
    <button ref={btnRef} onClick={toggle} title={title} aria-label={title} className={`text-[11px] rounded px-2 py-1 font-bold leading-none tracking-wider ${open?"bg-stone-800 text-white":"bg-stone-100 text-stone-600 hover:bg-stone-200"}`}>···</button>
    {open&&createPortal(
      <div style={{top:pos.top,right:pos.right}} className="fixed z-[95] bg-white border border-stone-200 rounded-lg shadow-lg py-1 min-w-[190px]" onClick={e=>e.stopPropagation()}>
        {vis.map((it,i)=><button key={i} onClick={()=>{setOpen(false);it.onClick&&it.onClick();}} title={it.title} className={`w-full text-left px-3 py-1.5 text-xs flex items-center gap-2 hover:bg-stone-50 ${it.danger?"text-rose-600":"text-stone-700"}`}>{it.label}{it.active&&<Check className="w-3.5 h-3.5 ml-auto text-emerald-600"/>}</button>)}
      </div>, document.body)}
  </>);
}
function Empty({icon:Icon,title,body}){return <div className="border border-dashed border-stone-300 rounded-lg p-12 text-center"><Icon className="w-8 h-8 text-stone-300 mx-auto mb-3"/><div className="text-stone-700 font-medium">{title}</div><div className="text-sm text-stone-400 mt-1 max-w-sm mx-auto">{body}</div></div>;}
function Info({k,v}){return <div className="flex justify-between gap-4 py-0.5 border-b border-stone-100"><span className="text-stone-400">{k}</span><span className="text-stone-800 text-right">{v}</span></div>;}
